document['addEventListener']('DOMContentLoaded',function(){const K=document['querySelectorAll']('.date-control');K['forEach']((T,m)=>{T['addEventListener']('keydown',function(h){if('Tab'===h['key']){if(h['preventDefault'](),h['shiftKey']){const x=K[m-0x1];x&&x['focus']();}else{const M=K[m+0x1];M&&M['focus']();}}});});});